import request from '@/utils/request'

// 辅助函数
const utils = {
  formatSalary(min, max) {
    if (!min && !max) return ''
    if (!max) return `${min}K以上`
    if (!min) return `${max}K以下`
    return `${min}K-${max}K`
  },

  formatCity(city) {
    if (!city || !city.length) return ''
    return city.map(c => c.label || c).join('-')
  }
}

// 基本信息相关接口
export const profile = {
  // 获取完整档案数据
  getComplete: () => {
    return request.get('/api/v1/users/profile/complete/')
  },

  // 获取基本信息
  getBasicInfo: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get',
      headers: {
        'Authorization': `Bearer ${localStorage.getItem('token')}`
      }
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    const cleanData = {
      name: data.name?.trim(),
      gender: data.gender,
      birth_date: data.birth_date,
      phone: data.phone?.trim(),
      email: data.email?.trim(),
      location: data.location?.trim(),
      personal_summary: data.personal_summary?.trim()
    }
    return request.post('/api/v1/users/profile/basic/', cleanData)
  },

  // 上传头像
  uploadAvatar: (formData) => {
    return request.post('/api/v1/users/profile/avatar/upload/', formData, {
      headers: { 'Content-Type': 'multipart/form-data' }
    })
  },

  // 获取完整度
  getCompleteness: () => {
    return request.get('/api/v1/users/profile/completeness/')
  },

  // 工作经历相关
  workExperience: {
    // 获取列表
    list: () => {
      return request.get('/api/v1/users/profile/work-experiences/')
    },

    // 添加
    add: (data) => {
      const cleanData = {
        company: data.company?.trim(),
        position: data.position?.trim(),
        department: data.department?.trim(),
        start_date: data.start_date,
        end_date: data.is_current ? null : data.end_date,
        is_current: Boolean(data.is_current),
        description: data.description?.trim(),
        achievements: data.achievements?.trim(),
        technologies: data.technologies?.trim()
      }
      return request.post('/api/v1/users/profile/work-experiences/', cleanData)
    },

    // 更新
    update: (id, data) => {
      const cleanData = {
        company: data.company?.trim(),
        position: data.position?.trim(),
        department: data.department?.trim(),
        start_date: data.start_date,
        end_date: data.is_current ? null : data.end_date,
        is_current: Boolean(data.is_current),
        description: data.description?.trim(),
        achievements: data.achievements?.trim(),
        technologies: data.technologies?.trim()
      }
      return request.put(`/api/v1/users/profile/work-experiences/${id}/`, cleanData)
    },

    // 删除
    delete: (id) => {
      return request.delete(`/api/v1/users/profile/work-experiences/${id}/`)
    }
  },

  // 求职意向相关
  jobIntention: {
    // 获取求职意向
    get: () => {
      return request.get('/api/v1/users/profile/job-intention/')
    },

    // 更新求职意向
    update: (data) => {
      const statusMap = {
        'open': 'unemployed_looking',
        'closed': 'employed_not_looking'
      }

      const cleanData = {
        job_type: data.job_type || '',
        expected_salary: data.expected_salary || '',
        expected_city: data.expected_city || '',
        job_status: statusMap[data.job_status] || data.job_status || 'employed_not_looking',
        industries: data.industries || ''
      }
      return request.put('/api/v1/users/profile/job-intention/', cleanData)
    }
  },

  // 简历优化相关
  optimization: {
    // 获取预览
    getPreview: () => {
      return request.get('/api/v1/users/profile/content-quality/')
    },

    // 确认优化
    confirm: (optimizationId) => {
      return request.post('/api/v1/users/profile/content-quality/confirm/', {
        optimization_id: optimizationId
      })
    },

    // 获取优化次数
    getCount: () => {
      return request.get('/api/v1/users/profile/content-quality/count/')
    }
  },

  // 布局配置
  layout: {
    update: (data) => {
      return request.put('/api/v1/users/profile/layout/', data)
    }
  }
}

// 只导出 profile 对象
export default profile
